function getGP(key, mtr) {
  var d = GP_DATA[key];
  var m = Math.max(0, Math.min(mtr, 540));
  var w = d.weights[m];
  var gross = 0, amc = 0, gmab = 0;
  for (var i = 0; i < d.funds.length; i++) {
    var f = FUNDS_MAP[d.funds[i]];
    gross += w[i] * f.gross;
    amc   += w[i] * f.charge;
    gmab  += w[i] * f.gmab;
  }
  return { gross: Math.min(gross, MAX_INVESTMENT_RETURN), amc: amc, gmab: gmab };
}

